{% extends "base.html" %}

{% block title %}Welcome | SCC{% endblock %}

{% block extra_head %}
<style>
  :root {
    --welcome-ink: #18212b;
    --welcome-muted: #5a6978;
    --welcome-panel: #ffffff;
    --welcome-surface: #f6fafc;
    --welcome-border: #d8e2ea;
    --welcome-accent: #0f766e;
    --welcome-accent-soft: #d7f4ef;
  }

  .welcome-shell {
    color: var(--welcome-ink);
  }

  .welcome-hero {
    border: 1px solid var(--welcome-border);
    border-radius: 1.2rem;
    background:
      radial-gradient(circle at 85% 5%, #e9faf6 0%, #e9faf600 48%),
      linear-gradient(180deg, #ffffff 0%, #f7fbfd 100%);
    box-shadow: 0 24px 50px rgba(10, 32, 49, 0.08);
    overflow: hidden;
  }

  .welcome-kicker {
    display: inline-flex;
    align-items: center;
    gap: 0.5rem;
    font-size: 0.78rem;
    font-weight: 700;
    letter-spacing: 0.06em;
    text-transform: uppercase;
    color: var(--welcome-accent);
    background: var(--welcome-accent-soft);
    border: 1px solid #b9e9de;
    border-radius: 999px;
    padding: 0.35rem 0.8rem;
  }

  .welcome-title {
    font-weight: 800;
    line-height: 1.1;
    margin-top: 0.9rem;
    margin-bottom: 0.8rem;
  }

  .welcome-lead {
    color: var(--welcome-muted);
    max-width: 70ch;
  }

  .welcome-cta {
    display: flex;
    flex-wrap: wrap;
    gap: 0.75rem;
    margin-top: 1.25rem;
  }

  .card-lite {
    border: 1px solid var(--welcome-border);
    border-radius: 1rem;
    background: var(--welcome-panel);
    box-shadow: 0 10px 28px rgba(10, 32, 49, 0.06);
  }

  .card-lite .card-title {
    font-weight: 700;
  }

  .list-check {
    margin: 0;
    padding-left: 0;
    list-style: none;
  }

  .list-check li {
    display: flex;
    gap: 0.65rem;
    margin-bottom: 0.55rem;
    color: var(--welcome-muted);
  }

  .list-check li i {
    color: var(--welcome-accent);
    margin-top: 0.1rem;
  }

  .auth-grid {
    display: grid;
    grid-template-columns: repeat(auto-fit, minmax(190px, 1fr));
    gap: 0.7rem;
  }

  .auth-chip {
    border: 1px solid var(--welcome-border);
    border-radius: 0.8rem;
    background: var(--welcome-surface);
    padding: 0.72rem 0.85rem;
    color: #20424f;
    text-decoration: none;
    font-weight: 600;
  }

  .auth-chip:hover {
    border-color: #aac3d1;
    background: #edf5fa;
    color: #113645;
  }

  .roadmap-note {
    border-left: 5px solid #0ea5e9;
    background: #eef8fd;
    border-radius: 0.8rem;
  }

  .muted-mini {
    color: var(--welcome-muted);
    font-size: 0.93rem;
  }
</style>
{% endblock %}

{% block content %}
<div class="welcome-shell">
  <section class="welcome-hero p-4 p-lg-5 mb-4">
    <span class="welcome-kicker">
      <i class="bi bi-heart-pulse" aria-hidden="true"></i>
      SCC Medical Workspace
    </span>
    <h1 class="welcome-title display-5">Welcome to Signs &amp; Current Complaints</h1>
    <p class="welcome-lead fs-5">
      SCC is an API-first medical helper workspace that runs on PC, Mac, and Linux.
      Use this page as your launch point for setup, account access, and day-to-day usage.
    </p>

    <div class="welcome-cta">
      <a class="btn btn-scc" href="/accounts/login/">
        <i class="bi bi-box-arrow-in-right me-1" aria-hidden="true"></i>Sign In
      </a>
      <a class="btn btn-outline-secondary" href="/accounts/signup/">
        <i class="bi bi-person-plus me-1" aria-hidden="true"></i>Create Account
      </a>
      <a class="btn btn-outline-dark" href="/admin/">
        <i class="bi bi-shield-lock me-1" aria-hidden="true"></i>Open Admin
      </a>
    </div>
  </section>

  <div class="row g-3 g-lg-4 mb-4">
    <div class="col-lg-4">
      <article class="card-lite h-100 p-3 p-lg-4">
        <h2 class="h5 card-title mb-3">1. Getting Started</h2>
        <ul class="list-check">
          <li><i class="bi bi-check2-circle"></i><span>Install SCC on your PC, Mac, or Linux machine.</span></li>
          <li><i class="bi bi-check2-circle"></i><span>Run the restart helper and open this welcome page.</span></li>
          <li><i class="bi bi-check2-circle"></i><span>Create your first user and verify login.</span></li>
        </ul>
      </article>
    </div>

    <div class="col-lg-4">
      <article class="card-lite h-100 p-3 p-lg-4">
        <h2 class="h5 card-title mb-3">2. Why Prompt-Based Flow</h2>
        <p class="muted-mini mb-2">
          Prompts help standardize how signs and complaints are captured, reducing missed details.
        </p>
        <ul class="list-check mb-0">
          <li><i class="bi bi-journal-medical"></i><span>Consistent input for every case.</span></li>
          <li><i class="bi bi-diagram-3"></i><span>Better structure for API processing.</span></li>
          <li><i class="bi bi-clipboard2-data"></i><span>Cleaner summaries and safer handover.</span></li>
        </ul>
      </article>
    </div>

    <div class="col-lg-4">
      <article class="card-lite h-100 p-3 p-lg-4">
        <h2 class="h5 card-title mb-3">3. Desktop Shortcut (Later)</h2>
        <p class="muted-mini mb-0">
          We will add step-by-step desktop shortcut instructions later for Windows, macOS, and Linux,
          so SCC can launch like a regular desktop app.
        </p>
      </article>
    </div>
  </div>

  <section class="card-lite p-3 p-lg-4 mb-4">
    <div class="d-flex flex-wrap justify-content-between align-items-center gap-2 mb-3">
      <h2 class="h5 card-title mb-0">Account Actions</h2>
      <span class="badge text-bg-light border">django-allauth enabled</span>
    </div>

    <div class="auth-grid">
      <a class="auth-chip" href="/accounts/signup/"><i class="bi bi-person-plus me-2"></i>Sign Up</a>
      <a class="auth-chip" href="/accounts/login/"><i class="bi bi-box-arrow-in-right me-2"></i>Sign In</a>
      <a class="auth-chip" href="/admin/password_change/"><i class="bi bi-key me-2"></i>Change Password</a>
      <a class="auth-chip" href="/admin/"><i class="bi bi-shield-check me-2"></i>Admin Portal</a>
      <a class="auth-chip" href="/accounts/logout/"><i class="bi bi-box-arrow-right me-2"></i>Log Out</a>
    </div>

    <p class="muted-mini mt-3 mb-0">
      Superuser creation remains a command-line setup step using Django manage commands.
      If you want, we can add a dedicated on-page guide next.
    </p>
  </section>

  <section class="roadmap-note p-3 p-lg-4">
    <h2 class="h6 fw-bold text-uppercase text-info-emphasis mb-2">Next Build Target</h2>
    <p class="mb-0 text-secondary">
      After this desktop welcome screen, we can design a dynamic phone-first SCC app view with Bootstrap
      responsive components and complaint entry flow optimized for smaller screens.
    </p>
  </section>
</div>
{% endblock %}
