<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <meta name="description" content="SCC - Signs and Current Complaints">
  <title>{% block title %}SCC{% endblock %}</title>

  <link rel="preconnect" href="https://fonts.googleapis.com">
  <link rel="preconnect" href="https://fonts.gstatic.com" crossorigin>
  <link href="https://fonts.googleapis.com/css2?family=Noto+Sans:wght@400;700&display=swap" rel="stylesheet">

  <link href="https://cdn.jsdelivr.net/npm/bootstrap@5.3.3/dist/css/bootstrap.min.css" rel="stylesheet"
        integrity="sha384-QWTKZyjpPEjISv5WaRU9OFeRpok6YctnYmDr5pNlyT2bRjXh0JMhjY6hW+ALEwIH" crossorigin="anonymous">

  <link href="https://cdn.jsdelivr.net/npm/bootstrap-icons@1.11.3/font/bootstrap-icons.min.css" rel="stylesheet">

  <style>
    :root {
      --scc-teal: #0f766e;
      --scc-teal-dk: #0d6b64;
      --scc-teal-soft: #ccf2ed;
      --scc-dark: #1a232e;
      --scc-muted: #4b5563;
      --scc-border: #d1d9e0;
      --scc-bg: #f4f7f9;
    }

    html { font-size: 18px; }

    body {
      font-family: 'Noto Sans', sans-serif;
      background-color: var(--scc-bg);
      color: var(--scc-dark);
      min-height: 100vh;
      display: flex;
      flex-direction: column;
    }

    @media (min-width: 992px) {
      html { font-size: 20px; }
    }

    .q-question {
      font-weight: 700;
      font-size: 1rem;
      max-width: 77ch;
    }

    .q-answer { font-size: 1rem; font-weight: 400; }

    .navbar { background-color: var(--scc-dark) !important; }
    .navbar-brand { font-weight: 700; font-size: 1.15rem; letter-spacing: .06em; }

    .scc-card {
      border-radius: 1rem;
      border: 1px solid var(--scc-border);
      box-shadow: 0 4px 24px rgba(0,0,0,.06);
      background-color: #fff;
    }

    .icon-tile {
      width: 52px;
      height: 52px;
      flex-shrink: 0;
      border-radius: .75rem;
      background-color: var(--scc-teal-soft);
      color: var(--scc-teal);
      display: flex;
      align-items: center;
      justify-content: center;
      font-size: 1.6rem;
    }

    .btn-scc {
      background-color: var(--scc-teal);
      color: #fff;
      font-weight: 700;
      border: none;
      border-radius: .75rem;
      padding: .7rem 1.5rem;
      font-size: 1rem;
    }

    .btn-scc:hover,
    .btn-scc:focus {
      background-color: var(--scc-teal-dk);
      color: #fff;
    }

    footer {
      font-size: .82rem;
      color: var(--scc-muted);
      margin-top: auto;
    }
  </style>

  {% block extra_head %}{% endblock %}
</head>
<body>

  <nav class="navbar navbar-expand-md navbar-dark" aria-label="Main navigation">
    <div class="container-fluid px-3">
      <a class="navbar-brand text-white" href="/">
        <i class="bi bi-clipboard2-pulse me-2" aria-hidden="true"></i>SCC
      </a>
      <button class="navbar-toggler" type="button"
              data-bs-toggle="collapse" data-bs-target="#navMain"
              aria-controls="navMain" aria-expanded="false" aria-label="Toggle navigation">
        <span class="navbar-toggler-icon"></span>
      </button>
      <div class="collapse navbar-collapse" id="navMain">
        <ul class="navbar-nav ms-auto mb-2 mb-md-0 gap-1">
          <li class="nav-item">
            <a class="nav-link" href="/">
              <i class="bi bi-house me-1" aria-hidden="true"></i>Home
            </a>
          </li>
          <li class="nav-item dropdown">
            <a class="nav-link dropdown-toggle" href="#" id="usefulTasksMenu" role="button" data-bs-toggle="dropdown" aria-expanded="false">
              <i class="bi bi-list-check me-1" aria-hidden="true"></i>Useful Tasks
            </a>
            <ul class="dropdown-menu dropdown-menu-end" aria-labelledby="usefulTasksMenu">
              <li><a class="dropdown-item" href="/accounts/signup/"><i class="bi bi-person-plus me-2"></i>Sign Up</a></li>
              <li><a class="dropdown-item" href="/accounts/login/"><i class="bi bi-box-arrow-in-right me-2"></i>Sign In</a></li>
              <li><a class="dropdown-item" href="/admin/password_change/"><i class="bi bi-key me-2"></i>Change Password</a></li>
              <li><a class="dropdown-item" href="/admin/"><i class="bi bi-shield-lock me-2"></i>Admin</a></li>
              <li><hr class="dropdown-divider"></li>
              <li><a class="dropdown-item" href="/#install-use"><i class="bi bi-laptop me-2"></i>Install and Use</a></li>
              <li><a class="dropdown-item" href="/#security"><i class="bi bi-lock me-2"></i>Security</a></li>
              <li><a class="dropdown-item" href="/#costs-free"><i class="bi bi-cash-coin me-2"></i>Costs Free</a></li>
            </ul>
          </li>
          {% if user.is_authenticated %}
          <li class="nav-item">
            <a class="nav-link" href="/accounts/profile/">
              <i class="bi bi-person me-1" aria-hidden="true"></i>Profile
            </a>
          </li>
          <li class="nav-item">
            <a class="nav-link" href="/accounts/logout/">
              <i class="bi bi-box-arrow-right me-1" aria-hidden="true"></i>Logout
            </a>
          </li>
          {% else %}
          <li class="nav-item">
            <a class="nav-link" href="/accounts/login/">
              <i class="bi bi-box-arrow-in-right me-1" aria-hidden="true"></i>Login
            </a>
          </li>
          <li class="nav-item">
            <a class="nav-link" href="/accounts/signup/">
              <i class="bi bi-person-plus me-1" aria-hidden="true"></i>Register
            </a>
          </li>
          {% endif %}
        </ul>
      </div>
    </div>
  </nav>

  {% if messages %}
  <div class="container mt-3">
    {% for message in messages %}
    <div class="alert alert-{{ message.tags }} alert-dismissible fade show" role="alert">
      {{ message }}
      <button type="button" class="btn-close" data-bs-dismiss="alert" aria-label="Dismiss"></button>
    </div>
    {% endfor %}
  </div>
  {% endif %}

  <main class="container py-4 py-lg-5 flex-grow-1">
    {% block content %}{% endblock %}
  </main>

  <footer class="border-top py-4 mt-4">
    <div class="container">
      <div class="row g-3 small">
        <div class="col-md-4" id="why-scc">
          <h2 class="h6 mb-2">Why SCC</h2>
          <p class="mb-1 text-body-secondary">Structured signs and complaints capture with prompt-based consistency.</p>
          <p class="mb-0 text-body-secondary">Suitable for family and single-person health workflows.</p>
        </div>
        <div class="col-md-4" id="install-use">
          <h2 class="h6 mb-2">Install and Use</h2>
          <ul class="list-unstyled mb-0 text-body-secondary">
            <li>PC, Mac, Linux support</li>
            <li>Sign Up / Sign In / Change Password</li>
            <li>Admin and API-first operation</li>
          </ul>
        </div>
        <div class="col-md-4" id="security">
          <h2 class="h6 mb-2">Security and Costs</h2>
          <p class="mb-1 text-body-secondary">Uses Django authentication, account access controls, and admin permissions.</p>
          <p class="mb-0 text-body-secondary" id="costs-free"><strong>Costs:</strong> Free.</p>
        </div>
      </div>
      <hr class="my-3">
      <div class="d-flex flex-wrap justify-content-between align-items-center gap-2 small text-body-secondary">
        <span>SCC &copy; {% now "Y" %} - Signs &amp; Current Complaints</span>
        <span id="designer-info">Designer info: SCC internal build workspace.</span>
      </div>
    </div>
